contract HorseyPilot {





    event NewProposal(uint8 methodId, uint parameter, address proposer);





    event ProposalPassed(uint8 methodId, uint parameter, address proposer);







    uint8 constant votingThreshold = 2;







    uint256 constant proposalLife = 7 days;







    uint256 constant proposalCooldown = 1 days;





    uint256 cooldownStart;





    address public jokerAddress;

    address public knightAddress;

    address public paladinAddress;





    address[3] public voters;





    uint8 constant public knightEquity = 40;

    uint8 constant public paladinEquity = 10;





    address public exchangeAddress;

    address public tokenAddress;





    mapping(address => uint) internal _cBalance;





    struct Proposal{

        address proposer;            

        uint256 timestamp;           

        uint256 parameter;           

        uint8   methodId;            

        address[] yay;               

        address[] nay;               

    }





    Proposal public currentProposal;





    bool public proposalInProgress = false;





    uint256 public toBeDistributed;





    bool deployed = false;





    constructor(

    address _jokerAddress,

    address _knightAddress,

    address _paladinAddress,

    address[3] _voters

    ) public {

        jokerAddress = _jokerAddress;

        knightAddress = _knightAddress;

        paladinAddress = _paladinAddress;



        for(uint i = 0; i < 3; i++) {

            voters[i] = _voters[i];

        }





        cooldownStart = block.timestamp - proposalCooldown;

    }





    function deployChildren(address stablesAddress) external {

        require(!deployed,"already deployed");



        exchangeAddress = new HorseyExchange();

        tokenAddress = new HorseyToken(stablesAddress);





        HorseyExchange(exchangeAddress).setStables(stablesAddress);



        deployed = true;

    }





    function transferJokerOwnership(address newJoker) external 

    validAddress(newJoker) {

        require(jokerAddress == msg.sender,"Not right role");

        _moveBalance(newJoker);

        jokerAddress = newJoker;

    }





    function transferKnightOwnership(address newKnight) external 

    validAddress(newKnight) {

        require(knightAddress == msg.sender,"Not right role");

        _moveBalance(newKnight);

        knightAddress = newKnight;

    }





    function transferPaladinOwnership(address newPaladin) external 

    validAddress(newPaladin) {

        require(paladinAddress == msg.sender,"Not right role");

        _moveBalance(newPaladin);

        paladinAddress = newPaladin;

    }





    function withdrawCeo(address destination) external 

    onlyCLevelAccess()

    validAddress(destination) {





        if(toBeDistributed > 0){

            _updateDistribution();

        }





        uint256 balance = _cBalance[msg.sender];





        if(balance > 0 && (address(this).balance >= balance)) {

            destination.transfer(balance);  

            _cBalance[msg.sender] = 0;

        }

    }





    function syncFunds() external {

        uint256 prevBalance = address(this).balance;

        HorseyToken(tokenAddress).withdraw();

        HorseyExchange(exchangeAddress).withdraw();

        uint256 newBalance = address(this).balance;



        toBeDistributed = toBeDistributed + (newBalance - prevBalance);

    }





    function getNobleBalance() external view

    onlyCLevelAccess() returns (uint256) {

        return _cBalance[msg.sender];

    }





    function makeProposal( uint8 methodId, uint256 parameter ) external

    onlyCLevelAccess()

    proposalAvailable()

    cooledDown()

    {

        currentProposal.timestamp = block.timestamp;

        currentProposal.parameter = parameter;

        currentProposal.methodId = methodId;

        currentProposal.proposer = msg.sender;

        delete currentProposal.yay;

        delete currentProposal.nay;

        proposalInProgress = true;



        emit NewProposal(methodId,parameter,msg.sender);

    }





    function voteOnProposal(bool voteFor) external 

    proposalPending()

    onlyVoters()

    notVoted() {



        require((block.timestamp - currentProposal.timestamp) <= proposalLife);

        if(voteFor)

        {

            currentProposal.yay.push(msg.sender);



            if( currentProposal.yay.length >= votingThreshold )

            {

                _doProposal();

                proposalInProgress = false;



                return;

            }



        } else {

            currentProposal.nay.push(msg.sender);



            if( currentProposal.nay.length >= votingThreshold )

            {

                proposalInProgress = false;

                cooldownStart = block.timestamp;

                return;

            }

        }

    }





    function _moveBalance(address newAddress) internal

    validAddress(newAddress) {

        require(newAddress != msg.sender);  

        _cBalance[newAddress] = _cBalance[msg.sender];

        _cBalance[msg.sender] = 0;

    }





    function _updateDistribution() internal {

        require(toBeDistributed != 0,"nothing to distribute");

        uint256 knightPayday = toBeDistributed / 100 * knightEquity;

        uint256 paladinPayday = toBeDistributed / 100 * paladinEquity;





        uint256 jokerPayday = toBeDistributed - knightPayday - paladinPayday;



        _cBalance[jokerAddress] = _cBalance[jokerAddress] + jokerPayday;

        _cBalance[knightAddress] = _cBalance[knightAddress] + knightPayday;

        _cBalance[paladinAddress] = _cBalance[paladinAddress] + paladinPayday;



        toBeDistributed = 0;

    }





    function _doProposal() internal {



        if( currentProposal.methodId == 0 ) HorseyToken(tokenAddress).setRenamingCosts(currentProposal.parameter);





        if( currentProposal.methodId == 1 ) HorseyExchange(exchangeAddress).setMarketFees(currentProposal.parameter);





        if( currentProposal.methodId == 2 ) HorseyToken(tokenAddress).addLegitRaceAddress(address(currentProposal.parameter));





        if( currentProposal.methodId == 3 ) HorseyToken(tokenAddress).addHorseIndex(bytes32(currentProposal.parameter));





        if( currentProposal.methodId == 4 ) {

            if(currentProposal.parameter == 0) {

                HorseyExchange(exchangeAddress).unpause();

                HorseyToken(tokenAddress).unpause();

            } else {

                HorseyExchange(exchangeAddress).pause();

                HorseyToken(tokenAddress).pause();

            }

        }





        if( currentProposal.methodId == 5 ) HorseyToken(tokenAddress).setClaimingCosts(currentProposal.parameter);





        if( currentProposal.methodId == 8 ){

            HorseyToken(tokenAddress).setCarrotsMultiplier(uint8(currentProposal.parameter));

        }





        if( currentProposal.methodId == 9 ){

            HorseyToken(tokenAddress).setRarityMultiplier(uint8(currentProposal.parameter));

        }



        emit ProposalPassed(currentProposal.methodId,currentProposal.parameter,currentProposal.proposer);

    }





    modifier validAddress(address addr) {

        require(addr != address(0),"Address is zero");

        _;

    }





    modifier onlyCLevelAccess() {

        require((jokerAddress == msg.sender) || (knightAddress == msg.sender) || (paladinAddress == msg.sender),"not c level");

        _;

    }







    modifier proposalAvailable(){

        require(((!proposalInProgress) || ((block.timestamp - currentProposal.timestamp) > proposalLife)),"proposal already pending");

        _;

    }







    modifier cooledDown( ){

        if(msg.sender == currentProposal.proposer && (block.timestamp - cooldownStart < 1 days)){

            revert("Cool down period not passed yet");

        }

        _;

    }





    modifier proposalPending() {

        require(proposalInProgress,"no proposal pending");

        _;

    }





    modifier notVoted() {

        uint256 length = currentProposal.yay.length;

        for(uint i = 0; i < length; i++) {

            if(currentProposal.yay[i] == msg.sender) {

                revert("Already voted");

            }

        }



        length = currentProposal.nay.length;

        for(i = 0; i < length; i++) {

            if(currentProposal.nay[i] == msg.sender) {

                revert("Already voted");

            }

        }

        _;

    }





    modifier onlyVoters() {

        bool found = false;

        uint256 length = voters.length;

        for(uint i = 0; i < length; i++) {

            if(voters[i] == msg.sender) {

                found = true;

                break;

            }

        }

        if(!found) {

            revert("not a voter");

        }

        _;

    }

}

contract JungleScratch is Owned {

    using SafeMath for uint;

    uint public LimitBottom = 0.02 ether;

    uint public LimitTop = 0.1 ether;



    address public Drawer;

    struct Game {

        bytes32 SecretKey_P;

        bool isPlay;

        bool isPay;

        uint Result;

        uint Time;

        address Buyer;

        uint value;

    }



    mapping (bytes32 => Game) public TicketPool;



    event SubmitTicket(bytes32 indexed SecretKey_D_hash, uint Bet_amount,bytes32 SecretKey_P, address Player);   

    event Result(bytes32 SecretKey_D_hash, bytes32 SecretKey_D,address Buyer, uint[] Bird_Result, uint Game_Result, uint time);

    event Pay(bytes32 indexed SecretKey_D_hash, address indexed Buyer, uint Game_Result);

    event Owe(bytes32 indexed SecretKey_D_hash, address indexed Buyer, uint Game_Result);

    event OwePay(bytes32 indexed SecretKey_D_hash, address indexed Buyer, uint Game_Result);



    function JungleScratch (address drawer_) public {

        Drawer = drawer_;

    }



    function submit(bytes32 secretKey_P, bytes32 secretKey_D_hash) payable public {

        require(msg.value == 0.02 ether || msg.value == 0.04 ether || msg.value == 0.06 ether || msg.value == 0.08 ether || msg.value == 0.1 ether);

        require(TicketPool[secretKey_D_hash].Time == 0);

        require(msg.value >= LimitBottom && msg.value <= LimitTop);

        uint check = msg.value.div(20000000000000000);

        require(check == 1 || check == 2 || check == 3 || check == 4 || check == 5);



        SubmitTicket(secretKey_D_hash, msg.value, secretKey_P, msg.sender);

        TicketPool[secretKey_D_hash] = Game(secretKey_P,false,false,0,block.timestamp,msg.sender,msg.value);

    }



    function award(bytes32 secretKey_D) public {



        require(Drawer == msg.sender);



        bytes32 secretKey_D_hash = keccak256(secretKey_D);



        Game local_ = TicketPool[secretKey_D_hash];



        require(local_.Time != 0 && !local_.isPlay);



        uint game_result = 0;

        uint[] memory RandomResult = new uint[](9);



        RandomResult[0] = uint(keccak256("Pig World is an AWESOME team",secretKey_D,'a',local_.SecretKey_P)) % 1000 + 1;

        RandomResult[1] = uint(keccak256(local_.SecretKey_P,"Every Game in our world is provably fair",secretKey_D,'b')) % 1000 + 1;

        RandomResult[2] = uint(keccak256('c',secretKey_D,"OMG it is a revolution dapp",local_.SecretKey_P)) % 1000 + 1;

        RandomResult[3] = uint(keccak256(secretKey_D,"hahahaha",local_.SecretKey_P,'d',"thanks for our team member and all player support.")) % 1000 + 1;

        RandomResult[4] = uint(keccak256("CC is our CEO",secretKey_D,"he can eat Betel nut",local_.SecretKey_P,'e')) % 1000 + 1;

        RandomResult[5] = uint(keccak256(20180612,"justin is our researcher",secretKey_D,"and he love little girl(at least 18, so it is ok)",local_.SecretKey_P,'f')) % 1000 + 1;

        RandomResult[6] = uint(keccak256("jeremy is our marketing",secretKey_D,'g',local_.SecretKey_P,"he is very humble and serious")) % 1000 + 1;

        RandomResult[7] = uint(keccak256('h',secretKey_D,"We are a geek team",local_.SecretKey_P,"we love blockchain")) % 1000 + 1;

        RandomResult[8] = uint(keccak256(secretKey_D,"hope you win a big prize",local_.SecretKey_P,"love you all!!!",'i')) % 1000 + 1;



        for (uint n = 0; n < 9; n++) {



            if(RandomResult[n]< 81){

                RandomResult[n] = 0;

            } else if(RandomResult[n]< 168){

                RandomResult[n] = 1;

            } else if(RandomResult[n]< 266){

                RandomResult[n] = 2;

            } else if(RandomResult[n]< 381){

                RandomResult[n] = 3;

            } else if(RandomResult[n]< 535){

                RandomResult[n] = 4;

            } else if(RandomResult[n]< 749){

                RandomResult[n] = 5;

            } else if(RandomResult[n]< 1001){

                RandomResult[n] = 6;

            }

        }



        for(uint nn = 0; nn < 6; nn++){

            uint count = 0;

            for(uint p = 0; p < 9; p++){

                if(RandomResult[p] == nn)

                    count ++;

            }



            if(count >= 3 && nn == 0)

                game_result = game_result.add(TicketPool[secretKey_D_hash].value.div(20000000000000000).mul(0.1 ether));



            if(count >= 3 && nn == 1)

                game_result = game_result.add(TicketPool[secretKey_D_hash].value.div(20000000000000000).mul(0.08 ether));



            if(count >= 3 && nn == 2)

                game_result = game_result.add(TicketPool[secretKey_D_hash].value.div(20000000000000000).mul(0.06 ether));



            if(count >= 3 && nn == 3)

                game_result = game_result.add(TicketPool[secretKey_D_hash].value.div(20000000000000000).mul(0.04 ether));



            if(count >= 3 && nn == 4)

                game_result = game_result.add(TicketPool[secretKey_D_hash].value.div(20000000000000000).mul(0.02 ether)); 



            if(count >= 3 && nn == 5)

                game_result = game_result.add(TicketPool[secretKey_D_hash].value.div(20000000000000000).mul(0.01 ether)); 

        }





        if(game_result != 0){

            TicketPool[secretKey_D_hash].Result = game_result;

            if (address(this).balance >= game_result && TicketPool[secretKey_D_hash].Buyer.send(game_result)) {

                TicketPool[secretKey_D_hash].isPay = true;

                Pay(secretKey_D_hash,TicketPool[secretKey_D_hash].Buyer, game_result);

            } else {

                Owe(secretKey_D_hash, TicketPool[secretKey_D_hash].Buyer, game_result);

                TicketPool[secretKey_D_hash].isPay = false;

            } 

         } else {

            TicketPool[secretKey_D_hash].isPay = true;

        }



        Result(secretKey_D_hash, secretKey_D, TicketPool[secretKey_D_hash].Buyer, RandomResult, game_result, block.timestamp);

        TicketPool[secretKey_D_hash].isPlay = true;

    }



    function () public payable {



    }



    function withdraw(uint withdrawEther_) public onlyOwner {

        msg.sender.transfer(withdrawEther_);

    }



    function changeLimit(uint _bottom, uint _top) public onlyOwner {

        LimitBottom = _bottom;

        LimitTop = _top;

    }



    function changeDrawer(address drawer_) public onlyOwner {

        Drawer = drawer_;

    }



    function getisPlay(bytes32 secretKey_D_hash) public constant returns (bool isplay){

        return TicketPool[secretKey_D_hash].isPlay;

    }



    function getTicketTime(bytes32 secretKey_D_hash) public constant returns (uint Time){

        return TicketPool[secretKey_D_hash].Time;

    }



    function chargeOwe(bytes32 secretKey_D_hash) public {

        require(!TicketPool[secretKey_D_hash].isPay);

        require(TicketPool[secretKey_D_hash].isPlay);

        require(TicketPool[secretKey_D_hash].Result != 0);



        if(address(this).balance >= TicketPool[secretKey_D_hash].Result){

            if (TicketPool[secretKey_D_hash].Buyer.send(TicketPool[secretKey_D_hash].Result)) {

                TicketPool[secretKey_D_hash].isPay = true;

                OwePay(secretKey_D_hash, TicketPool[secretKey_D_hash].Buyer, TicketPool[secretKey_D_hash].Result);

            }

        } 

    }

}

